/* ================================================================
   Theme Variables & Reset
   ================================================================ */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --bg-gradient: radial-gradient(circle at 50% 50%, #0d121f, #050811);
  --card-bg: rgba(15, 22, 42, 0.65);
  --card-border: rgba(255, 255, 255, 0.07);
  --input-bg: rgba(9, 14, 28, 0.6);
  --input-border: rgba(255, 255, 255, 0.12);
  --text-primary: #f8fafc;
  --text-secondary: #94a3b8;
  --text-muted: #64748b;
  --emerald: #10b981;
  --emerald-glow: rgba(16, 185, 129, 0.15);
  --blue: #3b82f6;
  --blue-glow: rgba(59, 130, 246, 0.15);
  --amber: #f59e0b;
  --amber-glow: rgba(245, 158, 11, 0.15);
  --rose: #f43f5e;
  --rose-glow: rgba(244, 63, 94, 0.15);
}

body {
  font-family: "Inter", -apple-system, BlinkMacSystemFont, sans-serif;
  font-size: 13px;
  color: var(--text-primary);
  background: var(--bg-gradient);
  background-attachment: fixed;
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
}

.wrap {
  padding: 24px;
  max-width: 1400px;
  margin: 0 auto;
}

/* Header */
.db-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
}

.brand-meta h1 {
  font-family: "Outfit", sans-serif;
  font-size: 22px;
  font-weight: 700;
  letter-spacing: -0.02em;
  background: linear-gradient(135deg, #ffffff 0%, #cbd5e1 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  margin-top: 4px;
}

.badge-brand {
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.1);
  color: var(--text-primary);
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 99px;
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.sync-indicator {
  font-size: 11px;
  color: var(--text-secondary);
  display: flex;
  align-items: center;
  gap: 6px;
  background: rgba(255, 255, 255, 0.03);
  padding: 6px 12px;
  border-radius: 99px;
  border: 1px solid rgba(255, 255, 255, 0.05);
}

.pulse-dot {
  width: 6px;
  height: 6px;
  background: var(--emerald);
  border-radius: 50%;
  box-shadow: 0 0 8px var(--emerald);
  animation: pulse 1.8s infinite;
}

@keyframes pulse {
  0% {
    transform: scale(0.9);
    opacity: 0.6;
  }
  50% {
    transform: scale(1.2);
    opacity: 1;
    box-shadow: 0 0 12px var(--emerald);
  }
  100% {
    transform: scale(0.9);
    opacity: 0.6;
  }
}
/* KPI */
.kpi-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 14px;
  margin-bottom: 24px;
}

.kpi {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 14px;
  padding: 16px 18px;
  backdrop-filter: blur(8px);
  position: relative;
  overflow: hidden;
  transition: transform 0.2s ease, border-color 0.2s ease;
}

.kpi::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: transparent;
}

.kpi:hover {
  transform: translateY(-2px);
  border-color: rgba(255, 255, 255, 0.12);
}

.kpi.green::before {
  background: var(--emerald);
}

.kpi.blue::before {
  background: var(--blue);
}

.kpi.amber::before {
  background: var(--amber);
}

.kpi.red::before {
  background: var(--rose);
}

.kpi-label {
  font-size: 10px;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  font-weight: 600;
  margin-bottom: 6px;
}

.kpi-val {
  font-family: "Outfit", sans-serif;
  font-size: 24px;
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.1;
}

.kpi-val.green {
  color: var(--emerald);
  text-shadow: 0 0 12px rgba(16, 185, 129, 0.1);
}

.kpi-val.blue {
  color: var(--blue);
  text-shadow: 0 0 12px rgba(59, 130, 246, 0.1);
}

.kpi-val.amber {
  color: var(--amber);
  text-shadow: 0 0 12px rgba(245, 158, 11, 0.1);
}

.kpi-val.red {
  color: var(--rose);
  text-shadow: 0 0 12px rgba(244, 63, 94, 0.1);
}

.kpi-sub {
  font-size: 11px;
  color: var(--text-muted);
  margin-top: 6px;
}

/* Tabs Container */
.tabs-container {
  border-bottom: 1px solid var(--card-border);
  padding-bottom: 2px;
  margin-bottom: 20px;
}

.tabs {
  display: flex;
  gap: 8px;
}

.tab {
  font-family: "Inter", sans-serif;
  font-size: 12px;
  font-weight: 600;
  padding: 8px 18px;
  border-radius: 8px 8px 0 0;
  border: none;
  cursor: pointer;
  background: transparent;
  color: var(--text-secondary);
  transition: all 0.2s ease;
  display: flex;
  align-items: center;
  gap: 8px;
  position: relative;
  top: 1px;
}

.tab:hover {
  color: var(--text-primary);
}

.tab.active {
  background: var(--card-bg);
  color: var(--text-primary);
  border: 1px solid var(--card-border);
  border-bottom: 1px solid #0d121f;
  box-shadow: 0 -4px 10px rgba(0, 0, 0, 0.15);
}

.tab svg {
  opacity: 0.7;
}

.tab.active svg {
  opacity: 1;
}

/* Panels */
.tab-panel.hidden {
  display: none;
}

.panel-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 14px;
  overflow: hidden;
  backdrop-filter: blur(8px);
}

/* Filters */
.filters-header {
  padding: 16px 20px;
  border-bottom: 1px solid var(--card-border);
  background: rgba(255, 255, 255, 0.01);
}

.filters {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
}

.filters select,
.filters input {
  font-size: 12px;
  height: 36px;
  padding: 0 12px;
  border: 1px solid var(--input-border);
  border-radius: 8px;
  background: var(--input-bg);
  color: var(--text-primary);
  outline: none;
  cursor: pointer;
  transition: all 0.15s ease;
}

.filters select:focus,
.filters input:focus {
  border-color: var(--blue);
  box-shadow: 0 0 0 2px rgba(59, 130, 246, 0.15);
}

.filters input {
  width: 220px;
  cursor: text;
}

.search-box-wrapper {
  position: relative;
  display: inline-block;
}

.search-box-wrapper input {
  padding-left: 32px;
}

.search-icon {
  position: absolute;
  left: 11px;
  top: 11px;
  color: var(--text-muted);
  pointer-events: none;
}

/* Table styling */
.table-wrap {
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
  table-layout: fixed;
}

thead {
  background: rgba(0, 0, 0, 0.2);
}

th {
  padding: 12px 18px;
  text-align: left;
  font-size: 11px;
  font-weight: 700;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  border-bottom: 1px solid var(--card-border);
  white-space: nowrap;
}

td {
  padding: 10px 18px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.03);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: rgba(255, 255, 255, 0.9);
}

tbody tr:last-child td {
  border-bottom: none;
}

tbody tr:hover td {
  background: rgba(255, 255, 255, 0.02);
}

/* Badges */
.badge {
  display: inline-block;
  font-size: 9px;
  font-weight: 700;
  padding: 3px 8px;
  border-radius: 6px;
  text-transform: uppercase;
  letter-spacing: 0.02em;
}

.badge-sale {
  background: rgba(16, 185, 129, 0.12);
  color: #34d399;
  border: 1px solid rgba(16, 185, 129, 0.15);
}

.badge-purchase {
  background: rgba(59, 130, 246, 0.12);
  color: #60a5fa;
  border: 1px solid rgba(59, 130, 246, 0.15);
}

.badge-sr {
  background: rgba(244, 63, 94, 0.12);
  color: #f87171;
  border: 1px solid rgba(244, 63, 94, 0.15);
}

.badge-pr {
  background: rgba(245, 158, 11, 0.12);
  color: #fbbf24;
  border: 1px solid rgba(245, 158, 11, 0.15);
}

/* Pagination */
.pagination {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 20px;
  font-size: 12px;
  color: var(--text-secondary);
  border-top: 1px solid var(--card-border);
  background: rgba(0, 0, 0, 0.1);
}

.pagination button {
  font-family: "Inter", sans-serif;
  font-weight: 600;
  font-size: 11px;
  padding: 6px 14px;
  border-radius: 8px;
  border: 1px solid var(--input-border);
  cursor: pointer;
  background: var(--input-bg);
  color: var(--text-primary);
  display: flex;
  align-items: center;
  gap: 6px;
  transition: all 0.15s ease;
}

.pagination button:hover:not(:disabled) {
  background: rgba(255, 255, 255, 0.06);
  border-color: rgba(255, 255, 255, 0.2);
}

.pagination button:disabled {
  opacity: 0.35;
  cursor: not-allowed;
}

.page-info {
  font-weight: 500;
}

.count-info {
  margin-left: auto;
  color: var(--text-muted);
  font-weight: 500;
}

/* Sections & Analytics Panels */
.section {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 14px;
  padding: 20px;
  backdrop-filter: blur(8px);
}

.section-title-wrap {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
}

.section-title {
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-secondary);
}

.two-col {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}

/* Custom Visualizations */
.chart-container {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.bar-row {
  display: flex;
  align-items: center;
  gap: 12px;
}

.bar-label {
  font-size: 12px;
  color: var(--text-primary);
  width: 140px;
  flex-shrink: 0;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.bar-bg {
  flex: 1;
  background: rgba(255, 255, 255, 0.04);
  border-radius: 6px;
  height: 12px;
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, 0.02);
}

.bar-fill {
  height: 100%;
  border-radius: 6px;
  transition: width 0.8s cubic-bezier(0.4, 0, 0.2, 1);
  box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
}

.bar-val {
  font-family: "Outfit", sans-serif;
  font-size: 12px;
  color: var(--text-secondary);
  min-width: 70px;
  text-align: right;
  font-weight: 600;
}

/* Scrollbar tuning */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.1);
  border-radius: 99px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.2);
}

@media (max-width: 850px) {
  .two-col {
    grid-template-columns: 1fr;
  }
  .bar-label {
    width: 110px;
  }
  .kpi-grid {
    grid-template-columns: repeat(2, 1fr);
  }
  .db-header {
    flex-direction: column;
    align-items: flex-start;
    gap: 12px;
  }
  .sync-indicator {
    align-self: flex-start;
  }
}

