/* ================================================================
   Thadi Brand History — Appsmith Custom Widget Redesigned  v3
   ================================================================ */

/* ── Helpers ── */
const fmt = v => '₹' + Number(v).toLocaleString('en-IN', {
  minimumFractionDigits: 2,
  maximumFractionDigits: 2
});
const fmtN = v => Number(v).toLocaleString('en-IN');
const shortName = n => n.replace('TH ', '').replace(' SYRUP', '');

/* ── State ── */
let txs = [];
let filtered = [];
let currentPage = 1;
const PAGE_SIZE = 12;

/* ================================================================
   ENTRY POINT — called on load and on every model update
   ================================================================ */
function init(brandData) {
  if (!brandData) return;
  txs = brandData.transactions || [];
  filtered = [...txs];
  buildKPIs(brandData);
  populateDropdowns();
  applyFilters(); // renders table
  buildAnalytics();
  buildMonthly(brandData);
}

/* ================================================================
   KPI CARDS
   ================================================================ */
function buildKPIs(d) {
  const s = d.summary;
  const gr = s.gross;
  const returnRate = (gr.sales_returns.qty / gr.sales.qty * 100).toFixed(2) + '%';
  const items = [{
    label: 'Net Sales',
    val: fmt(s.net.sales.amount),
    sub: fmtN(s.net.sales.qty) + ' units',
    cls: 'green'
  }, {
    label: 'Net Purchases',
    val: fmt(s.net.purchases.amount),
    sub: fmtN(s.net.purchases.qty) + ' units',
    cls: 'blue'
  }, {
    label: 'Gross Margin',
    val: s.margins.gross_margin_pct,
    sub: 'Net: ' + s.margins.net_realized_margin_pct,
    cls: 'amber'
  }, {
    label: 'Sales Returns',
    val: fmt(gr.sales_returns.amount),
    sub: fmtN(gr.sales_returns.qty) + ' units',
    cls: 'red'
  }, {
    label: 'Stock Value',
    val: fmt(d.stock_valuation.valuation),
    sub: fmtN(d.stock_valuation.qty) + ' on hand',
    cls: ''
  }, {
    label: 'Return Rate',
    val: returnRate,
    sub: 'of gross sales qty',
    cls: 'red'
  }];
  document.getElementById('kpiGrid').innerHTML = items.map(i => `
    <div class="kpi ${i.cls}">
      <div class="kpi-label">${i.label}</div>
      <div class="kpi-val ${i.cls}">${i.val}</div>
      <div class="kpi-sub">${i.sub}</div>
    </div>`).join('');
}

/* ================================================================
   TRANSACTIONS — dropdowns, filter, render
   ================================================================ */
function populateDropdowns() {
  const products = [...new Set(txs.map(t => t.product_name))].sort();
  const parties = [...new Set(txs.map(t => t.party_name))].sort();
  const months = [...new Set(txs.map(t => t.trans_date.slice(0, 7)))].sort().reverse();
  function fill(id, values) {
    const sel = document.getElementById(id);
    const cur = sel.value;
    while (sel.options.length > 1) sel.remove(1);
    values.forEach(v => {
      const o = document.createElement('option');
      o.value = o.textContent = v;
      sel.appendChild(o);
    });
    sel.value = cur;
  }
  fill('fProduct', products);
  fill('fParty', parties);
  fill('fMonth', months);
}
function applyFilters() {
  const type = document.getElementById('fType').value;
  const product = document.getElementById('fProduct').value;
  const party = document.getElementById('fParty').value;
  const month = document.getElementById('fMonth').value;
  const q = document.getElementById('fSearch').value.toLowerCase();
  filtered = txs.filter(t => (!type || t.trans_type === type) && (!product || t.product_name === product) && (!party || t.party_name === party) && (!month || t.trans_date.startsWith(month)) && (!q || t.product_name.toLowerCase().includes(q) || t.party_name.toLowerCase().includes(q)));
  currentPage = 1;
  renderTable();
}
function badgeCls(type) {
  return {
    'Sale': 'badge-sale',
    'Purchase': 'badge-purchase',
    'Sales Return': 'badge-sr',
    'Purchase Return': 'badge-pr'
  }[type] || '';
}
function badgeLbl(type) {
  return {
    'Sales Return': 'SR',
    'Purchase Return': 'PR'
  }[type] || type;
}
function renderTable() {
  const start = (currentPage - 1) * PAGE_SIZE;
  const rows = filtered.slice(start, start + PAGE_SIZE);
  const totalPages = Math.ceil(filtered.length / PAGE_SIZE) || 1;
  document.getElementById('txBody').innerHTML = rows.map(t => `
    <tr>
      <td>${t.trans_date.slice(5)}</td>
      <td><span class="badge ${badgeCls(t.trans_type)}">${badgeLbl(t.trans_type)}</span></td>
      <td title="${t.product_name}">${shortName(t.product_name)}</td>
      <td title="${t.party_name}">${t.party_name}</td>
      <td style="text-align:right;font-weight:600;">${t.qty}</td>
      <td style="text-align:right">₹${t.rate.toFixed(2)}</td>
      <td style="text-align:right;font-weight:600;">₹${t.total_amount.toFixed(0)}</td>
    </tr>`).join('');
  document.getElementById('pageInfo').textContent = `Page ${currentPage} of ${totalPages}`;
  document.getElementById('countInfo').textContent = `${filtered.length} records`;
  document.getElementById('btnPrev').disabled = currentPage === 1;
  document.getElementById('btnNext').disabled = currentPage >= totalPages;
}

/* ================================================================
   ANALYTICS
   ================================================================ */
function buildBars(id, data, colorFn) {
  const max = Math.max(...data.map(d => d.value), 1);
  document.getElementById(id).innerHTML = data.map(d => `
    <div class="bar-row">
      <div class="bar-label" title="${d.label}">${d.label}</div>
      <div class="bar-bg"><div class="bar-fill" style="width:${Math.round(d.value / max * 100)}%;background:${colorFn(d)}"></div></div>
      <div class="bar-val">${d.display}</div>
    </div>`).join('');
}
function buildAnalytics() {
  const sales = txs.filter(t => t.trans_type === 'Sale');
  const returns = txs.filter(t => t.trans_type === 'Sales Return');

  /* Top products by sales qty */
  const prodQty = {};
  sales.forEach(t => {
    prodQty[t.product_name] = (prodQty[t.product_name] || 0) + t.qty;
  });
  buildBars('topProducts', Object.entries(prodQty).sort((a, b) => b[1] - a[1]).slice(0, 6).map(([n, q]) => ({
    label: shortName(n),
    value: q,
    display: fmtN(q) + ' u'
  })), () => 'linear-gradient(90deg, #059669 0%, #10b981 100%)');

  /* Top customers by amount */
  const custAmt = {};
  sales.forEach(t => {
    custAmt[t.party_name] = (custAmt[t.party_name] || 0) + t.total_amount;
  });
  buildBars('topCustomers', Object.entries(custAmt).sort((a, b) => b[1] - a[1]).slice(0, 6).map(([n, a]) => ({
    label: n,
    value: a,
    display: '₹' + Math.round(a / 1000) + 'k'
  })), () => 'linear-gradient(90deg, #2563eb 0%, #3b82f6 100%)');

  /* Return rate per product */
  const saleQty = {},
    retQty = {};
  sales.forEach(t => {
    saleQty[t.product_name] = (saleQty[t.product_name] || 0) + t.qty;
  });
  returns.forEach(t => {
    retQty[t.product_name] = (retQty[t.product_name] || 0) + t.qty;
  });
  buildBars('returnRate', Object.keys(saleQty).map(p => ({
    label: shortName(p),
    value: (retQty[p] || 0) / saleQty[p] * 100
  })).sort((a, b) => b.value - a.value).slice(0, 6).map(d => ({
    ...d,
    display: d.value.toFixed(1) + '%'
  })), () => 'linear-gradient(90deg, #dc2626 0%, #f43f5e 100%)');

  /* Sales by pack size */
  const packAmt = {};
  sales.forEach(t => {
    const pack = t.product_name.includes('500ML') ? '500 ML' : '750 ML';
    packAmt[pack] = (packAmt[pack] || 0) + t.total_amount;
  });
  const packColors = {
    '750 ML': 'linear-gradient(90deg, #059669 0%, #10b981 100%)',
    '500 ML': 'linear-gradient(90deg, #2563eb 0%, #3b82f6 100%)'
  };
  const total = Object.values(packAmt).reduce((a, b) => a + b, 0);
  buildBars('catBreakdown', Object.entries(packAmt).map(([k, v]) => ({
    label: k,
    value: v,
    display: Math.round(v / total * 100) + '% · ₹' + Math.round(v / 1000) + 'k'
  })), d => packColors[d.label] || '#888');
}

/* ================================================================
   MONTHLY TRENDS
   ================================================================ */
function buildMonthly(d) {
  const active = (d.monthly_trends || []).filter(m => m.sales > 0 || m.purchase > 0);
  const maxNM = Math.max(...active.map(m => Math.abs(m.net_movement)), 1);
  document.getElementById('monthlyBars').innerHTML = active.map(m => `
    <div class="bar-row">
      <div class="bar-label">${m.month}</div>
      <div class="bar-bg">
        <div class="bar-fill" style="width:${Math.round(Math.abs(m.net_movement) / maxNM * 100)}%;background:${m.net_movement >= 0 ? 'linear-gradient(90deg, #059669 0%, #10b981 100%)' : 'linear-gradient(90deg, #dc2626 0%, #f43f5e 100%)'}"></div>
      </div>
      <div class="bar-val" style="color:${m.net_movement >= 0 ? '#10b981' : '#f43f5e'}; font-weight:700;">${fmt(m.net_movement)}</div>
    </div>`).join('');
  document.getElementById('monthlyBody').innerHTML = active.map(m => `
    <tr>
      <td>${m.month}</td>
      <td style="text-align:right">${fmt(m.sales)}</td>
      <td style="text-align:right">${fmt(m.purchase)}</td>
      <td style="text-align:right;color:#f87171">${fmt(m.sales_return)}</td>
      <td style="text-align:right;color:#fbbf24">${fmt(m.purchase_return)}</td>
      <td style="text-align:right;font-weight:700;color:${m.net_movement >= 0 ? '#10b981' : '#f43f5e'}">${fmt(m.net_movement)}</td>
    </tr>`).join('');
}

/* ================================================================
   TAB SWITCHING  ─ Add event listeners directly
   ================================================================ */
