['fType', 'fProduct', 'fParty', 'fMonth'].forEach(id => {
  document.getElementById(id).addEventListener('change', applyFilters);
});
document.getElementById('fSearch').addEventListener('input', applyFilters);
document.getElementById('btnPrev').addEventListener('click', function () {
  if (currentPage > 1) {
    currentPage--;
    renderTable();
  }
});
document.getElementById('btnNext').addEventListener('click', function () {
  const totalPages = Math.ceil(filtered.length / PAGE_SIZE) || 1;
  if (currentPage < totalPages) {
    currentPage++;
    renderTable();
  }
});

/* ================================================================
   APPSMITH MODEL BINDING
   ================================================================ */
appsmith.onReady(function () {
  init(appsmith.model.brandData);
});
appsmith.model.subscribe(function () {
  init(appsmith.model.brandData);
});

